#include <bits/stdc++.h>
using namespace std;

int gcd(int a, int b) {
    if (a == 0 || b == 0) return a + b;
    return gcd(b, a % b);
}

int main() {
    int n, q, a[100005];
    cin >> n >> q;
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }
    sort(a, a + n);
    int g = 0;
    for (int i = 1; i < n; i++) {
        g = gcd(g, a[i] - a[i - 1]);
    }
    for (int i = 1; i <= q; i++) {
        printf("%d\n", gcd(a[0] + i, g));
    }
    return 0;
}
